@@ -28,6 +28,9 @@ final class PathPrefixer

     public function stripPrefix(string $path): string
     {
+        if ( ! str_starts_with($path, $this->prefix)) {
+            throw new \InvalidArgumentException("Path '{$path}' does not start with expected prefix '{$this->prefix}'.");
+        }
         /* @var string */
         return substr($path, strlen($this->prefix));
     }
